/**
* Add a value to the data
* @param value the value to add
*/
public void addValue(double value) {
    sumImpl.increment(value);
    sumsqImpl.increment(value);
    minImpl.increment(value);
    maxImpl.increment(value);
    sumLogImpl.increment(value);
    secondMoment.increment(value);
    // If mean, variance or geomean have been overridden,
    // need to increment these
    if (!(meanImpl instanceof Mean)) {
        meanImpl.increment(value);
    }
    if (!(varianceImpl instanceof Variance)) {
        varianceImpl.increment(value);
    }
    if (!(geoMeanImpl instanceof GeometricMean)) {
        geoMeanImpl.increment(value);
    }
    n++;
}

patches.fixed_method:
public void addValue(double value) {
    sumImpl.increment(value);
    sumsqImpl.increment(value);
    minImpl.increment(value);
    maxImpl.increment(value);
    sumLogImpl.increment(value);
    secondMoment.increment(value);
    // If mean, variance or geomean have not been overridden,
    // need to increment these
    if (meanImpl != null && meanImpl instanceof Mean) {
        meanImpl.increment(value);
    }
    if (varianceImpl != null && varianceImpl instanceof Variance) {
        varianceImpl.increment(value);
    }
    if (geoMeanImpl != null && geoMeanImpl instanceof GeometricMean) {
        geoMeanImpl.increment(value);
    }
    n++;
}

public void addValue(double value) {
    sumImpl.increment(value);
    sumsqImpl.increment(value);
    minImpl.increment(value);
    maxImpl.increment(value);
    sumLogImpl.increment(value);
    secondMoment.increment(value);
    // Increment only if the implementations are instances of their default classes
    if (meanImpl instanceof Mean) {
        meanImpl.increment(value);
    }
    if (varianceImpl instanceof Variance) {
        varianceImpl.increment(value);
    }
    if (geoMeanImpl instanceof GeometricMean) {
        geoMeanImpl.increment(value);
    }
    n++;
}
